interface.signature:
Inputs: - files: List of file globs to upload as release assets - body: Release notes/description (optional, auto-generated if omitted) - tag_name: Auto-detected from trigger tag - draft: false (publish immediately) - prerelease: false (mark as stable release)
Environment: - GITHUB_TOKEN: Auto-provided by GitHub Actions (secrets.GITHUB_TOKEN)
Outputs: - Release URL: https://github.com/{user}/recipe/releases/tag/{tag} - Asset download URLs: https://github.com/{user}/recipe/releases/download/{tag}/{file}
